package com.bankapp;

import android.content.Context;
import android.content.SharedPreferences;
import android.os.Bundle;
import android.view.View;
import android.widget.Button;
import android.widget.TextView;
import android.widget.Toast;
import androidx.appcompat.app.AppCompatActivity;
import java.math.BigDecimal;
import java.math.RoundingMode;

public class BankingAppActivity extends AppCompatActivity {
    private static final String PREFS_NAME = "BankingPrefs";
    private static final String BALANCE_KEY = "account_balance";
    private static final String TRANSACTION_HISTORY_KEY = "transaction_history";
    
    private TextView balanceTextView;
    private Button depositButton;
    private Button withdrawButton;
    private Button transferButton;
    
    private SharedPreferences sharedPreferences;
    private BigDecimal currentBalance;
    
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_banking_app);
        
        initializeViews();
        sharedPreferences = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        loadAccountData();
        updateUI();
        
        setupClickListeners();
    }
    
    private void initializeViews() {
        balanceTextView = findViewById(R.id.balanceTextView);
        depositButton = findViewById(R.id.depositButton);
        withdrawButton = findViewById(R.id.withdrawButton);
        transferButton = findViewById(R.id.transferButton);
    }
    
    private void loadAccountData() {
        String balanceString = sharedPreferences.getString(BALANCE_KEY, "0.00");
        currentBalance = new BigDecimal(balanceString).setScale(2, RoundingMode.HALF_UP);
    }
    
    private void updateUI() {
        balanceTextView.setText(String.format("$%.2f", currentBalance));
    }
    
    private void setupClickListeners() {
        depositButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                performTransaction(100.00);
            }
        });
        
        withdrawButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                performTransaction(-50.00);
            }
        });
        
        transferButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                performTransaction(-25.00);
            }
        });
    }
    
    private void performTransaction(double amount) {
        BigDecimal newBalance = currentBalance.add(BigDecimal.valueOf(amount));
        
        if (newBalance.compareTo(BigDecimal.ZERO) >= 0) {
            currentBalance = newBalance;
            saveAccountData();
            updateUI();
            Toast.makeText(this, "Transaction successful", Toast.LENGTH_SHORT).show();
        } else {
            Toast.makeText(this, "Insufficient funds", Toast.LENGTH_SHORT).show();
        }
    }
    
    private void saveAccountData() {
        SharedPreferences.Editor editor = sharedPreferences.edit();
        editor.putString(BALANCE_KEY, currentBalance.toString());
        editor.apply();
    }
    
    @Override
    protected void onDestroy() {
        super.onDestroy();
        saveAccountData();
    }
}